p.m:
\displaystyle{\begin{aligned}
  \frac{{\frac{1}{m-1}+\frac{3}{m-1}}}{{3-\frac{1}{m+1}}} \amp = \frac{({\frac{1}{m-1}+\frac{3}{m-1}})\cdot{\left(m+1\right)\mathopen{}\left(m-1\right)}}{({3-\frac{1}{m+1}})\cdot{\left(m+1\right)\mathopen{}\left(m-1\right)}} \\
    \amp = \frac{{\frac{1}{m-1}\mathopen{}\left(m+1\right)\mathopen{}\left(m-1\right)+\frac{3}{m-1}\mathopen{}\left(m+1\right)\mathopen{}\left(m-1\right)}}{{3\mathopen{}\left(m+1\right)\mathopen{}\left(m-1\right)-\frac{1}{m+1}\mathopen{}\left(m+1\right)\mathopen{}\left(m-1\right)}} \\
    \amp = \frac{{m+1+3\mathopen{}\left(m+1\right)}}{{3\mathopen{}\left(m^{2}-1\right)-\left(m-1\right)}}, m \ne 1 \text{ and }  m \ne -1 \\
    \amp = \frac{{m+1+3m+3}}{{3m^{2}-3-m+1}}, m \ne 1 \text{ and }  m \ne -1 \\
    \amp = \frac{{4m+4}}{{3m^{2}-m-2}}, m \ne 1 \text{ and }  m \ne -1 \\
    \amp = {\frac{4\mathopen{}\left(m+1\right)}{\left(3m+2\right)\mathopen{}\left(m-1\right)}, m\ne -1}
\end{aligned}
    }
